node -e "
const jobs = require('./scenarios/fieldwork/fixtures/jobs.json');
const today = new Date('2026-07-14');
const windowEnd = new Date('2026-07-16');
const open = jobs.filter(j => j.completedAt === null);
console.log('open count', open.length);
const overdue = open.filter(j => j.status === 'overdue');
console.log('overdue count', overdue.length, overdue.map(j=>j.id));
const atRiskWindow = open.filter(j => new Date(j.slaDue) <= windowEnd);
console.log('atRiskWindow (<=07-16) count', atRiskWindow.length, atRiskWindow.map(j=>j.id+':'+j.slaDue+':'+j.status+':'+j.region));
const atRiskNotOverdue = atRiskWindow.filter(j=>j.status!=='overdue');
console.log('atRisk not-yet-overdue count', atRiskNotOverdue.length, atRiskNotOverdue.map(j=>j.id));
// region concentration among atRiskWindow (breach+atrisk combined)
const regionCounts = {};
atRiskWindow.forEach(j=>{regionCounts[j.region]=(regionCounts[j.region]||0)+1});
console.log('region counts (breach+at-risk)', regionCounts);
// unassigned + at risk (not overdue)
const unassignedAtRisk = atRiskNotOverdue.filter(j=>j.techId===null);
console.log('unassigned at-risk (not overdue)', unassignedAtRisk.length, unassignedAtRisk.map(j=>j.id));
// unassigned total open
const unassignedOpen = open.filter(j=>j.techId===null);
console.log('unassigned open total', unassignedOpen.length, unassignedOpen.map(j=>j.id));
// tech load: open jobs per tech
const techs = require('./scenarios/fieldwork/fixtures/technicians.json');
const loadByTech = {};
techs.forEach(t=>loadByTech[t.id]=0);
open.forEach(j=>{ if(j.techId) loadByTech[j.techId] = (loadByTech[j.techId]||0)+1; });
console.log('load by tech', loadByTech);
const maxTech = Object.entries(loadByTech).sort((a,b)=>b[1]-a[1])[0];
console.log('busiest tech', maxTech, techs.find(t=>t.id===maxTech[0]).name);
const idle = Object.entries(loadByTech).filter(([id,c])=>c===0);
console.log('idle techs', idle);
"

